// Global counter — anyone can mess with it
let count = 0;

function increment() {
  count++;
}

// Problem: count = 999 would break everything

codeComparison.new:
// Factory function with private state
function createCounter(startValue = 0) {
  let count = startValue; // PRIVATE!

  return {
    increment: () => ++count,
    decrement: () => --count,
    getValue: () => count,
    reset: () => { count = startValue; }
  };
}

let counter1 = createCounter(0);
let counter2 = createCounter(100);
// Two completely independent counters!
// counter1.count is undefined — it's private!

