function createBankAccount(accountName, initialBalance) {
  // PRIVATE variables - trapped in the closure
  let balance = initialBalance;
  let transactions = [];

  // PRIVATE helper function
  function addTransaction(type, amount) {
    transactions.push({
      type: type,
      amount: amount,
      date: new Date().toLocaleString(),
      balanceAfter: balance
    });
  }

  // PUBLIC methods - the only way to interact with the account
  return {
    getAccountName: () => accountName,
    getBalance: () => balance,

    deposit: function(amount) {
      if (typeof amount !== 'number' || amount <= 0) {
        return { success: false, message: 'Invalid amount' };
      }
      balance += amount;
      addTransaction('deposit', amount);
      return { success: true, message: `Deposited $${amount.toFixed(2)}` };
    },

    withdraw: function(amount) {
      // Your code: validate, check balance, update, add transaction
    },

    getHistory: () => [...transactions] // return a copy, not the original
  };
}

// Test it:
let myAccount = createBankAccount('Sarah', 1000);
console.log(myAccount.balance);     // undefined (private!)
console.log(myAccount.getBalance()); // 1000 (works!)

